('VNR_2021_parent_inventory_1', 'VNR', 2021, 'parent', 'Chi phí xây dựng cơ bản dở dang', 'construction_in_progress', 3071777834.0, NULL, 'Chi phí xây dựng cơ bản dở dang'),
('VNR_2021_parent_inventory_2', 'VNR', 2021, 'parent', 'Dự án Tincom Plaza Giải Phóng', 'real_estate_project', 5036625338.0, NULL, 'Khoản góp vốn hợp tác đầu tư dự án căn hộ cao cấp 35 tầng tại 360 Giải Phóng, Hà Nội. Chủ đầu tư là Công ty CP Tập đoàn Đầu tư và Thương mại Thăng Long. Dự án đã bị tạm ngừng thi công tòa nhà HH3 từ năm 2019 khi xây dựng đến tầng 14 do khó khăn tài chính của chủ đầu tư. Tổng Công ty nhận được 2.098.049.557 VND từ phân chia sản phẩm chuyển nhượng căn hộ tòa HH2 trong năm 2021.'),
('VNR_2021_parent_inventory_3', 'VNR', 2021, 'parent', 'Dự án 142 Định Công', 'real_estate_project', 6169373933.0, NULL, 'Chi phí phát sinh liên quan dự án hợp tác xây dựng khu nhà ở, dịch vụ và thương mại tại 142 Định Công, Hà Nội. Dự án đang chờ kết quả rà soát chuyển đổi mục đích sử dụng đất theo chỉ đạo của UBND Thành phố Hà Nội.'),
('VNR_2020_consolidated_inventory_0', 'VNR', 2020, 'consolidated', '9 căn hộ Hà Nội Paragon - Khu đô thị Dịch Vọng Hậu', 'finished_goods', 36895972638.0, 4547124138.0, '9 căn hộ nhận để trừ công nợ từ Công ty CP Xây dựng và Thương mại VT. Giá trị thẩm định tại ngày 31/12/2020 là 32.057.578.316 Đồng. Đã trích lập dự phòng giảm giá.'),
('VNR_2020_consolidated_inventory_1', 'VNR', 2020, 'consolidated', '1 căn hộ Hà Nội Paragon (nhà đầu tư hợp vốn)', 'finished_goods', 4039917818.0, 0.0, '1 căn hộ thuộc sở hữu nhà đầu tư hợp vốn, đang chờ hoàn thiện thủ tục pháp lý chuyển nhượng.'),
('VNR_2020_consolidated_inventory_2', 'VNR', 2020, 'consolidated', 'Dự án 142 Định Công', 'construction_in_progress', 14036123679.0, NULL, 'Khoản góp vốn đầu tư xây dựng khu nhà ở, dịch vụ và thương mại tại 142 Định Công. Dự án đang trong quá trình thực hiện thủ tục để đưa vào xây dựng.');
